const https = require('https');
const fs = require('fs');

const input = $input.first().json;

// Handle both Simplify ON and Simplify OFF payload formats
function extractHeader(input, headerName) {
  // Simplify OFF -- headers are in payload.headers array
  if (input.payload && input.payload.headers) {
    const header = input.payload.headers.find(function(h) {
      return h.name && h.name.toLowerCase() === headerName.toLowerCase();
    });
    return header ? header.value : '';
  }
  // Simplify ON -- fields are at top level
  if (headerName.toLowerCase() === 'from') return input.from || '';
  if (headerName.toLowerCase() === 'subject') return input.subject || '';
  return '';
}

function extractBody(input) {
  // Simplify ON
  if (input.snippet) return input.snippet;
  // Simplify OFF -- body is base64 encoded in payload.body.data
  if (input.payload && input.payload.body && input.payload.body.data) {
    try {
      return Buffer.from(input.payload.body.data, 'base64').toString('utf8').substring(0, 1000);
    } catch(e) {}
  }
  // Try parts for multipart emails
  if (input.payload && input.payload.parts) {
    for (let i = 0; i < input.payload.parts.length; i++) {
      const part = input.payload.parts[i];
      if (part.mimeType === 'text/plain' && part.body && part.body.data) {
        try {
          return Buffer.from(part.body.data, 'base64').toString('utf8').substring(0, 1000);
        } catch(e) {}
      }
    }
  }
  return '';
}

const fromHeader = extractHeader(input, 'from');
const subject = extractHeader(input, 'subject');
const body = extractBody(input);
const messageId = input.id || '';

// Basic spam filter
const fromLower = (typeof fromHeader === 'string' ? fromHeader : '').toLowerCase();
const subjectLower = (typeof subject === 'string' ? subject : '').toLowerCase();
const spamIndicators = ['unsubscribe', 'noreply@', 'no-reply@', 'newsletter@', 'marketing@', 'donotreply@', 'notifications@', 'alert@', 'bounce@'];
const isSpam = spamIndicators.some(function(s) { return fromLower.indexOf(s) !== -1; });
const isAutoReply = subjectLower.indexOf('out of office') !== -1 || subjectLower.indexOf('auto-reply') !== -1 || subjectLower.indexOf('automatic reply') !== -1;

if (isSpam || isAutoReply) {
  return [{ json: {
    route: 'SKIP', agent: 'None', priority: 'low',
    reason: 'Spam or auto-reply filtered',
    from: fromHeader, subject: subject, body: body.substring(0, 500),
    messageId: messageId, timestamp: new Date().toISOString(), claudeClassified: false
  }}];
}

// Load KAI-Netics context
let ctx = {};
try {
  ctx = JSON.parse(fs.readFileSync('/data/KAI_Context.json', 'utf8').replace(/^\uFEFF/, ''));
} catch(e) { ctx = {}; }

const verticals = ctx.verticals || {};
const verticalList = Object.entries(verticals).map(function(entry) {
  return entry[0] + ': ' + (entry[1].name || '');
}).join(', ');

const systemPrompt = 'You are Aidan, email router for KAI-Netics. Classify incoming emails and route to the correct agent.\n\n' +
'KAI-NETICS CONTEXT:\n' +
'Company: KAI-Netics -- drone services, AI platform, workforce development\n' +
'Entities: FP (Kevin Alexander International LLC dba KAI-Netics), EAF (nonprofit 501c3 pending), MONK (IP holding)\n' +
'Founder: Kevin Alexander Smith -- CISSP, PMP, CCNA, FAA Part 107 Operator\n' +
'Verticals: ' + verticalList + '\n\n' +
'ROUTING RULES:\n' +
'NOVA -- RFPs, solicitations, procurement notices, contract opportunities, vendor registration requests, any email asking KAI-Netics to bid or respond to a formal opportunity\n' +
'JORDAN -- Grants, funding opportunities, award notifications, SBIR/STTR, Maryland state grants, federal grants, nonprofit funding, LOI requests, grant deadlines\n' +
'IRIS -- Compliance deadlines, regulatory updates, FAA notices, IRS communications, SAM.gov, Maryland state filings, legal notices, license renewals, tax matters\n' +
'SCOUT -- BD leads, partnership inquiries, potential client outreach, conference invitations, ecosystem contacts, introductions, speaking opportunities\n' +
'GENERAL -- Everything else that does not clearly fit the above categories\n' +
'SKIP -- Spam, marketing, newsletters, auto-replies, promotional emails\n\n' +
'Respond with ONLY a JSON object, no other text:\n' +
'{"route":"NOVA|JORDAN|IRIS|SCOUT|GENERAL|SKIP","priority":"critical|high|medium|low","reason":"one sentence explanation","confidence":"high|medium|low"}';

const userMessage = 'Classify this email:\n\nFROM: ' + fromHeader + '\nSUBJECT: ' + subject + '\nBODY PREVIEW: ' + body.substring(0, 800);

const requestBody = JSON.stringify({
  model: 'claude-sonnet-4-6',
  max_tokens: 150,
  system: systemPrompt,
  messages: [{ role: 'user', content: userMessage }]
});

const options = {
  hostname: 'api.anthropic.com', port: 443,
  path: '/v1/messages', method: 'POST',
  headers: {
    'Content-Type': 'application/json',
    'x-api-key': $env.ANTHROPIC_API_KEY,
    'anthropic-version': '2023-06-01',
    'Content-Length': Buffer.byteLength(requestBody)
  }
};

let route = 'GENERAL';
let priority = 'medium';
let reason = 'Claude classification failed -- defaulting to GENERAL';
let confidence = 'low';
let claudeClassified = false;

try {
  const result = await new Promise(function(resolve, reject) {
    const req = https.request(options, function(res) {
      let d = '';
      res.on('data', function(c) { d += c; });
      res.on('end', function() { resolve({ status: res.statusCode, body: d }); });
    });
    req.on('error', reject);
    req.write(requestBody);
    req.end();
  });
  if (result.status === 200) {
    const parsed = JSON.parse(result.body);
    const text = parsed.content && parsed.content[0] && parsed.content[0].text || '';
    const clean = text.replace(/```json|```/g, '').trim();
    const classification = JSON.parse(clean);
    route = classification.route || 'GENERAL';
    priority = classification.priority || 'medium';
    reason = classification.reason || '';
    confidence = classification.confidence || 'medium';
    claudeClassified = true;
  }
} catch(e) {
  reason = 'Classification error: ' + e.message;
}

return [{ json: {
  route: route,
  agent: route === 'NOVA' ? 'Nova' : route === 'JORDAN' ? 'Jordan' : route === 'IRIS' ? 'Iris' : route === 'SCOUT' ? 'Scout' : 'Aidan',
  priority: priority,
  reason: reason,
  confidence: confidence,
  claudeClassified: claudeClassified,
  from: fromHeader,
  subject: subject,
  body: body.substring(0, 2000),
  messageId: messageId,
  timestamp: new Date().toISOString()
}}];

